var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고생했네. 물건은 전부 무사하더군.","JPN":"ご苦労だった。荷物はすべて無事であったな。","ENG":"Good work. All the cargo made it intact.","TWN":"辛苦了，東西都完好無缺。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"장난해? 우린 그쪽이 부탁한 물건 때문에 침식체한테 쫓겨서 죽을 뻔했다고!","JPN":"何が無事だ！　こっちはその荷物のせいで侵食体に追われて死ぬところだったんだぞ！","ENG":"Are you kidding me?! We almost died hauling your stuff!","TWN":"你在開玩笑嗎？為了送這些東西，我們被侵蝕體追殺，差點命都沒了！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쫓길 각오는 한 줄 알았네만.","JPN":"追われる覚悟はできているのかと思ったが。","ENG":"I assumed you were prepared for pursuit.","TWN":"我以為你們答應時就知道會有危險。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"계약에 침식체가 몰려들 거란 내용은 없었잖아!","JPN":"侵食体が押し寄せてくるなんて契約書には書いてなかったじゃないか！","ENG":"No one said C.O.s would swarm us!","TWN":"合約上沒有寫會被侵蝕體追殺吧！"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그건 그대가 계약을 따르지 않았기 때문일세.","JPN":"それはそなたが契約に従わなかったからである。","ENG":"That's because you didn't follow the contract.","TWN":"那是你自己沒有遵守合約。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이터니움을 셋으로 소분해서 서로 다른 시간에 배달해 달라는 지침을 따르지 않았더군.","JPN":"エタニウムを3つに小分けして別々の時間帯に配送するという指針があっただろう。","ENG":"You were supposed to deliver the Eternium in three separate runs.","TWN":"我叫你把永恆之金分成三份運送，你卻沒有照做。"},"stage":{"bg":"CITY_JUNGLE","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh…?","TWN":"嗯…？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"물론 세 차례에 걸쳐 배달할 물건을 그대처럼 한 번에 실어 나르면 비용은 훨씬 절감할 수 있겠지.","JPN":"無論、3回に分けて配送する荷物を、そなたのようにまとめて運ぶとなれば費用を大きく節減できる。","ENG":"Sure, it's cheaper to haul it all at once, like you did.","TWN":"當然，像你這樣把三次運送的東西一次運完，可以省下很多成本。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허나 이곳으로 오는 중턱 길목은 차원벽이 약해 작은 자극만으로도 침식을 끌어들인다네.","JPN":"しかしここに来る途中にある山腹道路は次元壁が脆く、少しの刺激で侵食をおびき寄せるのでな。","ENG":"But that mountain pass has a thin dimensional wall. Even the slightest change and the C.O.s will come running.","TWN":"但這裡，這條山路，次元壁很薄，只要一點點刺激都會引來侵蝕。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 정도 양의 이터니움을 한 번에 가져오면 침식체가 나타나는 건 당연한 결과지.","JPN":"あれだけの量のエタニウムをまとめて運べば、侵食体が現れるのは至極当然のことだ。","ENG":"You brought this on yourselves bringing that much Eternium at once.","TWN":"一次帶這麼多永恆之金，會出現侵蝕體是理所當然的。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CONVOY_NPC_RIFLE_NULL","text":{"KOREA":"대장… 계속 우겼다간 본전도 못 찾겠는데요?","JPN":"隊長……言い争ったところで勝つ見込みはありませんよ。","ENG":"Boss… we're not getting out of this with full pay if we keep complainin'.","TWN":"隊長…少說一句吧，免得到時候我們什麼連本錢都賺不回來。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"끙…","JPN":"ぐぬぬ……","ENG":"Ugh…","TWN":"嘖…"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"알겠어. 내 책임도 조금은 있으니 그 부분은 넘어가지.","JPN":"まあ、そこは俺の責任も少しはあるからいいとしてだ。","ENG":"Fine. I'll take my share of the blame.","TWN":"好吧。這部分我也有點責任，就不跟你計較了。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CONVOY_NPC_RIFLE_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DRIVER_NPC_NULL_14","text":{"KOREA":"잠깐. 의뢰인에게 그런 요청이 있었단 얘기, 난 처음 듣는데?!","JPN":"待て。依頼人からそんな要望があったなんて話、俺は初耳だが！？","ENG":"Hold up. I didn't hear about any three runs part.","TWN":"等一下，我怎麼不知道委託人有這麼說過？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"윽…","JPN":"ぐっ……","ENG":"Guh…","TWN":"呃…"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"아, 알겠어! 위험수당 더 쳐주면 되잖아!","JPN":"わ、分かった！　危険手当をもっとつけてやるから！","ENG":"All right, fine! I'll tack on hazard pay. Happy?!","TWN":"好啦好啦！我再多貼錢給你啦！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"쳇, 돈 좀 아끼려다가 본전도 못 찾게 생겼군.","JPN":"ちっ、ケチって済まそうとしたら、元も取れそうにないな。","ENG":"Damn it. Trying to cut corners cost me everything.","TWN":"嘖，本來想省點錢，結果得不償失。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DRIVER_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기요-","JPN":"あの～","ENG":"Hey.","TWN":"那個…"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"뭐? 또 왜?","JPN":"何だ？　まだ何かあるのか？","ENG":"What now?!","TWN":"幹嘛？又怎麼了？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"제가 목숨 걸고 아저씨들을 지켜줬는데, 설마 맨입으로 넘어가려는 건 아니죠?","JPN":"まさかおじさんたち、ただで助けてもらったなんて思ってないですよね？","ENG":"You don't think I saved your butts for free, right?","TWN":"你們該不會以為我救你們是免費的吧？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그… 그러니까…","JPN":"その……それは……","ENG":"S-so…","TWN":"這…這個…"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"아가씨가 우리 사정 좀 봐줘! 이미 탄약 값도 안 남는다고!","JPN":"こっちの事情も汲んでくれよ！　こんなんじゃ弾代も残らないぞ！","ENG":"Oh, come on! Cut us some slack! We barely have enough for ammo!","TWN":"小妹妹，你也體諒一下我們！這樣我們連子彈的錢都賺不回來！"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그거야 멋대로 요청사항을 어긴 아저씨들 사정…","JPN":"それは勝手に要望を無視したおじさんたちが悪い……","ENG":"Well, you broke the contract. So…","TWN":"誰叫你們自己不遵守合約…"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…이라고 매몰차게 굴 수도 있지만, 다른 방법이 있긴 해요.","JPN":"……と、冷たく当たるのもできますけど。一応、別の方法もあるんです。","ENG":"…I could just be ruthless about it, but I have another idea.","TWN":"…我是可以這麼說，但還有別的方法。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"다른 방법? 그게 뭔데?","JPN":"別の方法？　なんだそれは？","ENG":"Another idea? What is it?","TWN":"別的方法？是什麼？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"후후, 돈이 없으면 몸으로 떼워야죠.","JPN":"ふふ……お金で払えないなら、体で払ってもらわないと。","ENG":"Hehe. If you can't pay up, work it off.","TWN":"呵呵，付不起錢的話，就用身體來償還吧。"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"모, 몸으로…?","JPN":"か、体で……？","ENG":"W-work it off…?","TWN":"用，用身體…？"},"stage":{"bg":"CITY_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"Whew…","TWN":"呼…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"이봐! 설치하란 거 다 했어! 전부 끝난 거겠지?","JPN":"おい！　言われたものは全部設置したぞ！　これで終わりだよな？","ENG":"Hey! We installed everything you asked for! We're done, right?!","TWN":"喂！你要裝的我都裝好了！應該結束了吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"일단은요. 고생했어요.","JPN":"とりあえずはですね。お疲れ様でした。","ENG":"For now. Nice work.","TWN":"暫時是，辛苦了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"이 장치들은 대체 정체가 뭐길래 침식지대 한복판에 깔아두는 거야?","JPN":"侵食地帯のど真ん中にセッティングするのか……？　この装置はいったい何なんだ？","ENG":"So what are these things anyway? Why set them up in the middle of a Corrupted Area?","TWN":"這些裝置到底是什麼東西，竟然要安裝在侵蝕地帶的中心？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"음…","JPN":"うーん……","ENG":"Hmm…","TWN":"嗯…"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부, 이거 말해도 돼?","JPN":"師匠、言っていい？","ENG":"Master, can I tell them?","TWN":"師父，這可以說嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"자랑은 아니지만 숨길 이유도 없지.","JPN":"自慢するような話ではないが、隠す理由もない。","ENG":"Not much point keeping it secret.","TWN":"雖然沒什麼好炫耀的，但也沒什麼好隱瞞的。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 설치하는 건 <color=#ffd34c>과거로 가기 위한 장치</color>란 걸세.","JPN":"我らが設置しているものは、<color=#ffd34c>過去へ向かうための装置</color>である。","ENG":"We're setting up a <color=#ffd34c>device to the past</color>. Simple as that.","TWN":"我們安裝的是<color=#ffd34c>回到過去的裝置</color>。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"…괴짜들이랑 엮였구만.","JPN":"……とんだ変人と関わってしまったな。","ENG":"…I'm working with lunatics.","TWN":"…遇到怪人了。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그게 뭔진 몰라도, 괜히 작동시켰다가 우리까지 위험해지는 건 아니겠지?","JPN":"それがどういう物かは知らないが、作動したら俺たちまで危ない目に遭ったりしないだろうな？","ENG":"Just tell me we're not gonna get killed when this thing turns on.","TWN":"那是什麼？隨便啟動我們不會有危險吧？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"원리는 간단하네. 그대들이 가져온 이터니움을 매개로 특수한 에너지를 포집하고 그걸 이용해 과거로 가는 것이지.","JPN":"原理は単純だ。そなたらが持ってきたエタニウムを媒介に、特殊なエネルギーを集め、それを利用して過去へ行く。","ENG":"It's simple. You brought the Eternium. It attracts a special energy we can use to open the way back.","TWN":"原理很簡單。利用你們帶來的永恆之金收集特殊的能量，然後利用它回到過去。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"과거로 가는 특수한 에너지…? 그런 게 이런 침식지대에 있단 말이야?","JPN":"過去に行く特殊なエネルギー……？　そんなものが侵食地帯にあるのか？","ENG":"Special energy for time travel…? That was just sitting here in the Corrupted Area?","TWN":"回到過去的特殊能量…？那種東西竟然存在於侵蝕地帶嗎？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대들도 알겠지만, 이곳 산간지역엔 주기적으로 먹비가 쏟아지거든.","JPN":"そなたも承知のことと思うが、この山間地域には周期的に墨雨が激しく降る。","ENG":"These mountains get hit by the Ink Rain regularly.","TWN":"你應該也知道，這裡的山區會週期性地降下墨雨。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"사람 죽이는 걸로 악명 높은 먹비에… 그런 대단한 에너지가 있었다고?","JPN":"人を殺すことで悪名高いあの墨雨に……そんなすごいエネルギーがあるだと？","ENG":"You're saying that Ink Rain, notorious for killing humans… actually has energy like that?","TWN":"惡名昭彰的墨雨…竟然有這麼厲害的能量？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 악명 때문에 지금껏 제대로 된 조사가 이뤄진 적 없지만, 사실 먹비는 침식파 뿐만 아니라 특별한 에너지를 품고 있어.","JPN":"その悪名のせいでまともな調査が行われていなかったわけだが、墨雨は侵食波だけでなく特殊なエネルギーも宿しているのだ。","ENG":"Its notoriety scared off proper research. But the Ink Rain holds more than Corruption rays. It holds a special energy.","TWN":"正因為它的惡名，所以從來沒有人好好調查過，但其實墨雨不只帶有侵蝕波，還有著特殊的能量。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우린 그걸 <color=#ffd34c>과거로 향하는 가능성을 품은 힘</color>이라 부른다네.","JPN":"我らはそれを<color=#ffd34c>過去へ向かう可能性を秘めた力</color>と呼んでいる。","ENG":"We call it the <color=#ffd34c>Possibility to the past</color>.","TWN":"我們稱它為<color=#ffd34c>蘊含著回到過去的可能力量</color>。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"직관적이긴 한데… 이름이 좀 길지 않나?","JPN":"分かりやすいけど……ちょっと名前が長すぎないか？","ENG":"Straightforward name… Kinda long, though.","TWN":"雖然很直觀…但名字是不是有點長？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"거 봐, 사부. 나만 그렇게 느끼는 게 아니라니깐?","JPN":"聞いた？師匠。やっぱり長いって。","ENG":"Told you, Master. I'm not the only one who thinks that.","TWN":"你看吧，師父。不只我這麼覺得。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여하튼 우린 지난 1년 간 <color=#ffd34c>와류흔</color>이라 불리는 먹비의 중심지를 찾아다녔어.","JPN":"とにかく、我らはこの1年間<color=#ffd34c>渦流痕</color>と呼ばれる墨雨の中心地を探し回った。","ENG":"Anyway, we spent the last year hunting down <color=#ffd34c>Vortex Scars</color>. Spots where the Ink Rain pools.","TWN":"總之，過去一年我們一直在尋找被稱為<color=#ffd34c>渦流痕</color>的墨雨中心地帶。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 중 하나인 이곳에 <color=#ffd34c>과.위.장</color>을 설치해 <color=#ffd34c>과.위.힘</color>을 포집하는 게 목표일세.","JPN":"その1つであるここに<color=#ffd34c>過向装</color>を設置し、<color=#ffd34c>過向力</color>を集めることが目標である。","ENG":"This is one of them. The plan is to deploy our <color=#ffd34c>DTP</color> and collect <color=#ffd34c>PTP</color>.","TWN":"我們的目標是在其中一個地方安裝<color=#ffd34c>回裝置</color>，來收集<color=#ffd34c>回力量</color>。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"전부 이상하게 줄여 부르기 시작했다.","JPN":"妙な感じに略し始めちゃったよ。","ENG":"He's started giving everything weird acronyms.","TWN":"開始用一些奇妙的縮寫。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그거 굉장히 위험하게 들리는데. 지금 갑자기 먹비가 내리고 그러진 않겠지?","JPN":"なんだか物騒だな。今突然ここに墨雨が降り出したりしないだろうな？","ENG":"Sounds risky. The Ink Rain's not gonna just drop on us, is it?","TWN":"這聽起來很危險。現在不會突然下墨雨吧？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"걱정 말게. 지금껏 관측한 바에 따르면, 이곳의 비는 나름의 규칙성을 따르고 있으니.","JPN":"心配はいらん。これまでの観測によれば、ここの墨雨にはそれなりの規則性がある。","ENG":"Relax. We've tracked it and found that it has a pattern.","TWN":"別擔心。根據我們目前的觀測，這裡的雨有著自己的規則。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지금은 내리지 않을 걸세. 아마도.","JPN":"今すぐには降らん。おそらく。","ENG":"Shouldn't hit us now. Probably.","TWN":"現在不會下的。應該吧。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"아마도라니! 그럼 당장 내릴 가능성도 있다는 거잖아!","JPN":"おそらくとはなんだ！　降る可能性もあるってことじゃないか！","ENG":"\\"Probably\\"?! So it could hit us?!","TWN":"應該吧？！那不就代表隨時都可能下嗎！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"세상에 100%의 가정이란 게 어디 있겠나.","JPN":"世の中に100％というのは存在しないものだからな。","ENG":"Nothing in this world is ever certain.","TWN":"沒有什麼是100%的。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"자, 조금만 더 힘내요. 이제 다섯 군데만 더 설치하면 되니까.","JPN":"ほら、もうちょっと頑張って。あと5か所だけ設置してくれれば終わりですから。","ENG":"Come on, hang in there. Only five more to go.","TWN":"好了，再加把勁，只剩下五個地方要安裝。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"뭐? 이런 장치가 다섯 개나 더 있다고?!","JPN":"何！？　こんな装置がまだ5つもあるのか！？","ENG":"What?! Five more?!","TWN":"什麼？這種裝置還有五個？！"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"조만간 먹비가 내릴만한 지점 후보에 전부 설치하는 걸세.","JPN":"近いうちに墨雨が降りそうなスポットにはすべて設置するのだ。","ENG":"We'll place them wherever the Ink Rain is likely to fall.","TWN":"我們要把它們安裝在所有可能下墨雨的地方。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"먹비는 자주 내리는 것이 아니기에 가능성을 최대한 높이는 편이 좋아.","JPN":"墨雨はそう頻繁に降るものではないゆえ、可能性は最大限に高めておいたほうがよかろう。","ENG":"It's rare enough we can't waste any chance.","TWN":"墨雨不常下，所以我們要盡量提高可能性。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CONVOY_NPC_SHIELD_NULL","text":{"KOREA":"그렇게까지 해서… 대체 뭘 성공시키려는 건데?","JPN":"そこまでやって……いったい何がしたいんだ？","ENG":"Going through all this trouble… just to pull what off?","TWN":"你們這麼辛苦…到底是想完成什麼？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"<color=#ffd34c>과.위.힘</color>을 모을 이유가 달리 있겠나.","JPN":"<color=#ffd34c>過向力</color>を集める理由など1つしかあるまい。","ENG":"Why gather <color=#ffd34c>PTP</color> if not to go back?","TWN":"收集<color=#ffd34c>回力量</color>還能有什麼願因？"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"당연히 과거로 가는 것이 목적이지.","JPN":"当然、過去へ行くことが目的だ。","ENG":"That's the goal. To go to back to the past.","TWN":"當然就是要回到過去。"},"stage":{"bg":"COUNTERSIDE_WELL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONVOY_NPC_SHIELD_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};